er\">S/ {{totals.t_quotations}}</td>\r\n                                <td class=\"text-center\">S/ {{totals.t_contracts}}</td>\r\n                                <td class=\"text-center\">S/ {{totals.t_income}}</td>\r\n                                <td class=\"text-center\">S/ {{totals.t_purchases}}</td>\r\n                                <td class=\"text-center\">S/ {{totals.t_expenses}}</td>\r\n                            </tr>\r\n                        </tfoot>\r\n                    </table> \r\n                </div>\r\n            </div>\r\n        </div>\r\n\r\n    </div>\r\n</template>\r\n<style>\r\n.font-custom{\r\n    font-size:15px !important\r\n}\r\n</style>\r\n<script>\r\n\r\n    import moment from 'moment'\r\n    import queryString from 'query-string'\r\n\r\n    export default {\r\n        props: {\r\n            resource: String,\r\n            applyCustomer: { type : Boolean, required: false, default: false}\r\n        },\r\n        data () {\r\n            return {\r\n                loading_submit:false,\r\n                loading_search:false,\r\n                columns: [],\r\n                records: [],\r\n                pagination: {},\r\n                search: {},\r\n                totals: {},\r\n                payment_types: [],\r\n                destination_types: [],\r\n                form: {},\r\n                pickerOptionsDates: {\r\n                    disabledDate: (time) => {\r\n                        time = moment(time).format('YYYY-MM-DD')\r\n                        return this.form.date_start > time\r\n                    }\r\n                },\r\n                pickerOptionsMonths: {\r\n                    disabledDate: (time) => {\r\n                        time = moment(time).format('YYYY-MM')\r\n                        return this.form.month_start > time\r\n                    }\r\n                },\r\n                sellers: []\r\n            }\r\n        },\r\n        computed: {\r\n        },\r\n        created() {\r\n            this.initForm()\r\n            this.$eventHub.$on('reloadData', () => {\r\n                this.getRecords()\r\n            })\r\n        },\r\n        async mounted () { \r\n\r\n            await this.getRecords()\r\n\r\n        },\r\n        methods: {\r\n            clickDownload(type) {\r\n                let query = queryString.stringify({\r\n                    ...this.form\r\n                });\r\n                window.open(`/${this.resource}/${type}/?${query}`, '_blank');\r\n            },\r\n            customIndex(index) {\r\n                return index + 1\r\n            },\r\n            initForm(){\r\n\r\n                this.form = { \r\n                    period: 'month',\r\n                    date_start: moment().format('YYYY-MM-DD'),\r\n                    date_end: moment().format('YYYY-MM-DD'),\r\n                    month_start: moment().format('YYYY-MM'),\r\n                    month_end: moment().format('YYYY-MM'),\r\n                }\r\n\r\n            },  \r\n            async getRecordsByFilter(){\r\n\r\n                this.loading_submit = await true\r\n                await this.getRecords()\r\n                this.loading_submit = await false\r\n\r\n            },\r\n            getRecords() {\r\n                return this.$http.get(`/${this.resource}/records?${this.getQueryParameters()}`).then((response) => {\r\n\r\n                    if(this.resource == 'finances/payment-method-types'){\r\n                        this.records = response.data.records\r\n                        this.totals = response.data.totals\r\n                    }else{\r\n                        this.records = response.data\r\n                    }\r\n\r\n                    this.loading_submit = false\r\n                });\r\n\r\n            },\r\n            getQueryParameters() {\r\n                return queryString.stringify({\r\n                    ...this.form\r\n                })\r\n            },\r\n\r\n            changeD